    if (node == NULL)
        app_error("malloc failed");

    node->name = copy_name(name);
    node->cnts = *cnts;
    node->next = NULL;

    if (*head == NULL || strcmp(name, (*head)->name) < 0) {
        node->next = *head;
        *head = node;
        return true;
